import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Order } from '../../data/models';

interface DeliveryLine {
  ref: string;
  description: string;
  rdd: string;
  ssd: string;
  status: 'on-track' | 'slipping' | 'shipped';
}

interface ExpediteEntry {
  date: string;
  actor: string;
  note: string;
}

@Component({
  selector: 'app-order-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './order-detail.component.html',
  styleUrl: './order-detail.component.css',
})
export class OrderDetailComponent {
  id = inject(ActivatedRoute).snapshot.paramMap.get('id') ?? '';
  order = computed<Order | undefined>(() => this.seed.orderById(this.id));

  // Illustrative per-line delivery breakdown (mockup).
  lines: DeliveryLine[] = [
    { ref: 'Line 001', description: 'Emax 2 E6.2 4000A ACB', rdd: '2026-08-30', ssd: '2026-09-18', status: 'slipping' },
    { ref: 'Line 002', description: 'Tmax XT6 800A feeders (x8)', rdd: '2026-08-30', ssd: '2026-08-28', status: 'on-track' },
    { ref: 'Line 003', description: 'SafeGear MV section', rdd: '2026-08-15', ssd: '2026-08-14', status: 'shipped' },
  ];

  // Illustrative expedite audit log (mockup).
  expediteLog: ExpediteEntry[] = [
    { date: '2026-07-06', actor: 'You', note: 'Escalated to ABB scheduler — requested slot recovery on E6.2 line.' },
    { date: '2026-07-02', actor: 'ABB Ops', note: 'Acknowledged slippage; new SSD candidate under review.' },
  ];

  statusBadge(status: Order['status']): string {
    switch (status) {
      case 'confirmed': return 'badge-info';
      case 'in-production': return 'badge-warning';
      case 'shipped': return 'badge-success';
      case 'delivered': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  lineBadge(status: DeliveryLine['status']): string {
    switch (status) {
      case 'shipped': return 'badge-success';
      case 'slipping': return 'badge-danger';
      case 'on-track': return 'badge-success';
      default: return 'badge-neutral';
    }
  }

  constructor(public seed: SeedService) {}
}
